# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using UnityEngine.UI;

public class PlayerController : MonoBehaviour
{
    public int health = 100; // Public variable to store player health
    public int currency = 0; // Public variable to store player currency
    public float damageMultiplier = 1.0f; // Multiplier for calculated damage

    private const int baseDamage = 10;
    private const int priceForHealingPotion = 50;
    private const int priceForShield = 100;

    private void Update()
    {
        if (Input.GetMouseButtonDown(0))
        {
            TakeDamage(baseDamage);
        }
    }

    public void TakeDamage(float damage)
    {
        health -= (int)(damage * damageMultiplier);
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
    }

    public void SpendCurrency(int amount, int price)
    {
        if (currency >= price)
        {
            AddCurrency(-price); // Remove currency
            MakePurchase(price);
        }
    }

    private void MakePurchase(int price)
    {
        switch (price)
        {
            case priceForHealingPotion:
                HealPlayer();
                break;
            case priceForShield:
                EquipShield();
                break;
        }
    }

    public void HealPlayer()
    {
        health = Mathf.Min(health + 50, 100);
    }

    private void EquipShield()
    {
        damageMultiplier *= 0.5f;
    }
}